 */
package io.strimzi.operator.cluster.model;

import io.fabric8.kubernetes.api.model.Service;
import io.fabric8.kubernetes.api.model.ServicePort;
import io.strimzi.api.kafka.model.common.jmx.KafkaJmxOptionsBuilder;
import io.strimzi.api.kafka.model.kafka.Kafka;
import io.strimzi.api.kafka.model.kafka.KafkaBuilder;
import io.strimzi.api.kafka.model.kafka.listener.GenericKafkaListenerBuilder;
import io.strimzi.api.kafka.model.kafka.listener.KafkaListenerType;
import io.strimzi.api.kafka.model.nodepool.KafkaNodePool;
import io.strimzi.api.kafka.model.nodepool.KafkaNodePoolBuilder;
import io.strimzi.api.kafka.model.nodepool.ProcessRoles;
import io.strimzi.certs.OpenSslCertManager;
import io.strimzi.operator.cluster.KafkaVersionTestUtils;
import io.strimzi.operator.cluster.PlatformFeaturesAvailability;
import io.strimzi.operator.cluster.model.nodepools.NodePoolUtils;
import io.strimzi.operator.common.Reconciliation;
import io.strimzi.operator.common.model.Ca;
import io.strimzi.operator.common.model.ClientsCa;
import io.strimzi.operator.common.model.ClusterCa;
import io.strimzi.operator.common.model.PasswordGenerator;
import io.strimzi.platform.KubernetesVersion;
import org.junit.jupiter.api.Test;

import java.util.List;
import java.util.Map;

import static org.hamcrest.CoreMatchers.is;
import static org.hamcrest.CoreMatchers.notNullValue;
import static org.hamcrest.MatcherAssert.assertThat;

public class NamedPortVerificationTest {

    private final String namespace = "test-namespace";
    private final String cluster = "test-cluster";
    private final Reconciliation reconciliation = new Reconciliation("test-trigger", Kafka.RESOURCE_KIND, namespace, cluster);
    private final PlatformFeaturesAvailability pfa = new PlatformFeaturesAvailability(false, KubernetesVersion.MINIMAL_SUPPORTED_VERSION);

    @Test
    public void testKafkaServiceUsesNamedPorts() {
        Kafka kafka = new KafkaBuilder()
                .withNewMetadata()
                    .withName(cluster)
                    .withNamespace(namespace)
                .endMetadata()
                .withNewSpec()
                    .withNewKafka()
                        .withListeners(
                                new GenericKafkaListenerBuilder()
                                        .withName("plain")
                                        .withPort(9092)
                                        .withType(KafkaListenerType.INTERNAL)
                                        .withTls(false)
                                        .build(),
                                new GenericKafkaListenerBuilder()
                                        .withName("tls")
                                        .withPort(9093)
                                        .withType(KafkaListenerType.INTERNAL)
                                        .withTls(true)
                                        .build())
                        .withReplicas(3)
                        .withNewEphemeralStorage()
                        .endEphemeralStorage()
                        .withNewJmxOptions()
                            .withAuthentication(new KafkaJmxOptionsBuilder().build().getAuthentication())
                        .endJmxOptions()
                    .endKafka()
                    .withNewZookeeper()
                        .withReplicas(3)
                        .withNewEphemeralStorage()
                        .endEphemeralStorage()
                    .endZookeeper()
                .endSpec()
                .build();

        KafkaNodePool pool = new KafkaNodePoolBuilder()
                .withNewMetadata()
                    .withName("pool")
                    .withNamespace(namespace)
                .endMetadata()
                .withNewSpec()
                    .withReplicas(3)
                    .withRoles(ProcessRoles.BROKER)
                    .withNewEphemeralStorage()
                    .endEphemeralStorage()
                .endSpec()
                .build();

        Map<String, KafkaPool> nodePools = NodePoolUtils.createKafkaPools(
                reconciliation,
                kafka,
                List.of(pool),
                Map.of(),
                Map.of(),
                KafkaVersionTestUtils.DEFAULT_ZOOKEEPER_VERSION_CHANGE,
                false,
                pfa);

        ClusterCa clusterCa = new ClusterCa(
                reconciliation,
                new OpenSslCertManager(),
                new PasswordGenerator(10, "a", "a"),
                cluster,
                null,
                null);
        clusterCa.createRenewOrReplace(namespace, cluster, Map.of(), Map.of(), Map.of(), null, true);

        ClientsCa clientsCa = new ClientsCa(
                reconciliation,
                new OpenSslCertManager(),
                new PasswordGenerator(10, "a", "a"),
                null,
                null,
                null,
                null,
                365,
                30,
                true,
                null);
        clientsCa.createRenewOrReplace(namespace, cluster, Map.of(), Map.of(), Map.of(), null, true);

        KafkaCluster kc = KafkaCluster.fromCrd(
                reconciliation,
                kafka,
                nodePools.values().stream().toList(),
                Map.of(),
                Map.of(),
                KafkaVersionTestUtils.DEFAULT_ZOOKEEPER_VERSION_CHANGE,
                KafkaMetadataConfigurationState.ZK,
                null,
                pfa);

        // Test bootstrap service
        Service bootstrapService = kc.generateService();
        assertThat(bootstrapService, is(notNullValue()));
        assertThat(bootstrapService.getSpec().getPorts().size() > 0, is(true));

        for (ServicePort port : bootstrapService.getSpec().getPorts()) {
            // Verify that targetPort is a string (named port) not an integer
            assertThat("Port " + port.getName() + " should use named targetPort",
                    port.getTargetPort().getStrVal(), is(notNullValue()));
            assertThat("Port " + port.getName() + " targetPort should match port name",
                    port.getTargetPort().getStrVal(), is(port.getName()));
        }

        // Test headless service
        Service headlessService = kc.generateHeadlessService();
        assertThat(headlessService, is(notNullValue()));
        assertThat(headlessService.getSpec().getPorts().size() > 0, is(true));

        for (ServicePort port : headlessService.getSpec().getPorts()) {
            // Verify that targetPort is a string (named port) not an integer
            assertThat("Port " + port.getName() + " should use named targetPort",
                    port.getTargetPort().getStrVal(), is(notNullValue()));
            assertThat("Port " + port.getName() + " targetPort should match port name",
                    port.getTargetPort().getStrVal(), is(port.getName()));
        }
    }
}

